const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const item = $input.item.json;

// Drive success: item has an 'id' field
if (item.id) {
  return {
  json: {
    docUrl: `https://drive.google.com/file/d/${item.id}/view?usp=sharing`,
    fileId: item.id,
    driveSuccess: true
  }
};
}

// Drive failed or returned no id — use fallback
warn('Drive upload failed or returned no file ID. Using fallback docUrl.');
return {
  json: {
    docUrl: 'https://drive.google.com',
    fileId: null,
    driveSuccess: false
  }
};

