// Node 4 — parse multiple OpenAI reporting responses
// Language: JavaScript
// Mode: Run once for all items

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const allItems = $input.all();

if (allItems.length === 0) {
  throw new Error('No input items received');
}

log('Total OpenAI responses to process:', allItems.length);

const results = allItems.map((item, index) => {
  const response = item.json;

  // Guard API errors per item
  if (response.error) {
    throw new Error(
      `Item ${index}: OpenAI API error: ` + response.error.message
    );
  }

  if (!response.choices || response.choices.length === 0) {
    throw new Error(
      `Item ${index}: No choices returned: ` +
      JSON.stringify(response).slice(0, 300)
    );
  }

  // Extract the brief — Markdown text not JSON
  const briefMarkdown = response.choices[0].message.content;


// Schema validation
if (!briefMarkdown || briefMarkdown.trim().length === 0) {
  throw new Error(`Item ${index}: OpenAI returned empty brief content`);
}

const minWordCount = 100;
const wordCount = briefMarkdown.split(/\s+/).length;
if (wordCount < minWordCount) {
  throw new Error(
    `Item ${index}: Brief is suspiciously short (${wordCount} words, expected at least ${minWordCount}). ` +
    'Possible truncation or hallucination.\nPreview: ' + briefMarkdown.slice(0, 200)
  );
}

const requiredSections = ['##', 'RAG', 'risk'];
const missingSections = requiredSections.filter(s => !briefMarkdown.includes(s));
if (missingSections.length > 0) {
  warn(`Item ${index}: Brief may be missing expected sections. Missing markers: ${missingSections.join(', ')}`);
  // warn only — don't throw, brief structure may vary
}



  log(`Item ${index} brief length:`, briefMarkdown.length);
  log(`Item ${index} preview:`, briefMarkdown.slice(0, 200));

  // Detect overall RAG from first 300 characters
  const ragMatch = briefMarkdown
    .slice(0, 300)
    .match(/\b(RED|AMBER|GREEN)\b/i);

  const overallRag = ragMatch
    ? ragMatch[1].toLowerCase()
    : 'amber';

  log(`Item ${index} overall RAG:`, overallRag);

  return {
    json: {
      briefMarkdown,
      overallRag,
      wordCount:   briefMarkdown.split(/\s+/).length,
      generatedAt: new Date().toISOString(),
      itemIndex:   index
    }
  };
});

log('Total briefs parsed:', results.length);

return results;

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };

const items = $input.all();

if (items.length === 0) {
  throw new Error('Return to Main Workflow: Merge produced no output items.');
}

// Merge combines by position:
// slot 0 → Drive Result Handler → docUrl, fileId, driveSuccess
// slot 1 → Code in JavaScript1  → briefMarkdown, overallRag, wordCount, generatedAt

const driveData = items[0]?.json ?? {};
const briefData = items[0]?.json ?? {};

// Validate drive data
if (!driveData.docUrl) {
  warn('docUrl missing from Drive slot — using fallback.');
}

// Validate brief data
if (!briefData.briefMarkdown || briefData.briefMarkdown.trim() === '') {
  throw new Error('Return to Main Workflow: briefMarkdown is missing or empty. Cannot return to main workflow.');
}

log('docUrl:', driveData.docUrl);
log('driveSuccess:', driveData.driveSuccess);
log('overallRag:', briefData.overallRag);
log('wordCount:', briefData.wordCount);

return [{
  json: {
    // Drive fields
    docUrl:        driveData.docUrl       ?? 'https://drive.google.com',
    fileId:        driveData.fileId       ?? null,
    driveSuccess:  driveData.driveSuccess ?? false,

    // Brief fields
    briefMarkdown: briefData.briefMarkdown,
    overallRag:    briefData.overallRag   ?? 'amber',
    wordCount:     briefData.wordCount    ?? 0,
    generatedAt:   briefData.generatedAt  ?? new Date().toISOString(),
  }
}];
